import React, { useState, useEffect } from "react";

const NewGamePage = () => {
  const [minute, setMinute] = useState(0);
  const [log, setLog] = useState([]);
  const [isPlaying, setIsPlaying] = useState(false);

  useEffect(() => {
    let interval;
    if (isPlaying) {
      interval = setInterval(() => {
        setMinute((prev) => {
          if (prev < 90) return prev + 1;
          clearInterval(interval);
          setIsPlaying(false);
          return prev;
        });
        if (Math.random() < 0.2) generateOpportunity();
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const generateOpportunity = () => {
    const isAttack = Math.random() < 0.5;
    if (isAttack) {
      const direction = prompt(
        "¡Oportunidad a favor! ¿Dónde quieres chutar? (izquierda, derecha, medio)"
      );
      const result = Math.random() < 0.66 ? "¡Gol!" : "¡Fallaste!";
      setLog((prev) => [
        ...prev,
        `Minuto ${minute}: Atacaste por ${direction}. Resultado: ${result}`,
      ]);
    } else {
      const direction = prompt(
        "¡Oportunidad en contra! ¿Dónde te lanzas? (izquierda, derecha, medio)"
      );
      const result = Math.random() < 0.33 ? "¡Paraste el tiro!" : "¡Gol en contra!";
      setLog((prev) => [
        ...prev,
        `Minuto ${minute}: El enemigo atacó. Elegiste ${direction}. Resultado: ${result}`,
      ]);
    }
  };

  const startGame = () => {
    setMinute(0);
    setLog([]);
    setIsPlaying(true);
  };

  return (
    <div>
      <h1>Emulador de Partido de Fútbol</h1>
      <p>Minuto actual: {minute}</p>
      <button onClick={startGame} disabled={isPlaying}>
        {isPlaying ? "Jugando..." : "Iniciar Partido"}
      </button>
      <div>
        <h2>Registro del Partido</h2>
        <ul>
          {log.map((entry, index) => (
            <li key={index}>{entry}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default NewGamePage;
